362→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
363→  LET $query = string::lowercase(string::trim($q));
364→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
365→
366→  LET $task_rows = SELECT
367→    id,
368→    "task" AS kind,
369→    title AS text,
370→    extraction_confidence AS confidence,
371→    source_message AS sourceMessage,
372→    priority,
373→    created_at
374→  FROM task
375→  WHERE workspace = $workspace
376→    AND extraction_confidence != NONE
377→    AND string::contains(string::lowercase(title), $query)
378→  ORDER BY created_at DESC
379→  LIMIT $safe_limit;
380→
381→  LET $decision_rows = SELECT
382→    id,
383→    "decision" AS kind,
384→    summary AS text,
385→    extraction_confidence AS confidence,
386→    source_message AS sourceMessage,
387→    priority,
388→    created_at
389→  FROM decision
390→  WHERE workspace = $workspace
391→    AND extraction_confidence != NONE
392→    AND string::contains(string::lowercase(summary), $query)
393→  ORDER BY created_at DESC
394→  LIMIT $safe_limit;
395→
396→  LET $question_rows = SELECT
397→    id,
398→    "question" AS kind,
399→    text AS text,
400→    extraction_confidence AS confidence,
401→    source_message AS sourceMessage,
402→    priority,
403→    created_at
404→  FROM question
405→  WHERE workspace = $workspace
406→    AND extraction_confidence != NONE
407→    AND string::contains(string::lowercase(text), $query)
408→  ORDER BY created_at DESC
409→  LIMIT $safe_limit;
410→
411→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
412→};
