414→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
415→  LET $query = string::lowercase(string::trim($q));
416→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
