470→DEFINE FUNCTION fn::conversation_recent($conversation: record<conversation>, $limit: int) {
471→  LET $safe_limit = math::min([math::max([$limit, 1]), 50]);
472→  RETURN SELECT id, role, text, createdAt
473→  FROM message
474→  WHERE conversation = $conversation
475→  ORDER BY createdAt DESC
476→  LIMIT $safe_limit;
477→};
