479→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
480→  RETURN SELECT
481→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
482→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
483→  FROM $entity;
484→};
