 65→/** List active decisions for a project, optionally filtered by area/category */
 66→export async function listProjectDecisions(input: {
 67→  surreal: Surreal;
 68→  workspaceRecord: RecordId<"workspace", string>;
 69→  projectRecord: RecordId<"project", string>;
 70→  area?: string;
 71→}): Promise<{
 72→  confirmed: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 73→  provisional: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 74→  contested: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 75→}> {
 76→  const areaFilter = input.area
 77→    ? `AND category = $area`
 78→    : "";
 79→
 80→  const [rows] = await input.surreal
 81→    .query<[DecisionRow[]]>(
 82→      `SELECT id, summary, status, rationale, decided_at, category, priority, created_at
 83→       FROM decision
 84→       WHERE workspace = $workspace
 85→         AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)
 86→         ${areaFilter}
 87→       ORDER BY created_at DESC LIMIT 50;`,
 88→      {
 89→        workspace: input.workspaceRecord,
 90→        project: input.projectRecord,
 91→        ...(input.area ? { area: input.area } : {}),
 92→      },
 93→    )
 94→    .collect<[DecisionRow[]]>();
 95→
 96→  type DecisionItem = { id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string };
 97→  const confirmed: DecisionItem[] = [];
 98→  const provisional: DecisionItem[] = [];
 99→  const contested: DecisionItem[] = [];
100→
101→  for (const d of rows) {
102→    const item: DecisionItem = {
103→      id: toId(d.id),
104→      summary: d.summary,
105→      status: d.status,
106→      ...(d.rationale ? { rationale: d.rationale } : {}),
107→      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
108→      ...(d.category ? { category: d.category } : {}),
109→    };
110→
111→    if (d.status === "contested") contested.push(item);
112→    else if (d.status === "provisional" || d.status === "inferred") provisional.push(item);
113→    else if (d.status === "confirmed") confirmed.push(item);
114→  }
115→
116→  return { confirmed, provisional, contested };
117→}
