408→/** Compute and apply subtask rollup on a parent task */
409→async function computeSubtaskRollup(
410→  surreal: Surreal,
411→  parentRecord: RecordId<"task", string>,
412→): Promise<string> {
413→  const [subtaskRows] = await surreal
414→    .query<[SubtaskRow[]]>(
415→      `SELECT id, title, status
416→       FROM task
417→       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent);`,
418→      { parent: parentRecord },
419→    )
420→    .collect<[SubtaskRow[]]>();
421→
422→  if (subtaskRows.length === 0) return "unknown";
423→
424→  const allCompleted = subtaskRows.every((s) => s.status === "done" || s.status === "completed");
425→  const anyBlocked = subtaskRows.some((s) => s.status === "blocked");
426→  const anyInProgress = subtaskRows.some((s) => s.status === "in_progress");
427→  const allTodo = subtaskRows.every((s) => s.status === "todo");
428→
429→  let derivedStatus: string;
430→
431→  if (allCompleted) derivedStatus = "completed";
432→  else if (anyBlocked && anyInProgress) derivedStatus = "in_progress";
433→  else if (anyBlocked) derivedStatus = "blocked";
434→  else if (anyInProgress) derivedStatus = "in_progress";
435→  else if (allTodo) derivedStatus = "todo";
436→  else derivedStatus = "in_progress";
437→
438→  await surreal.update(parentRecord).merge({
439→    status: derivedStatus,
440→    updated_at: new Date(),
441→  });
442→
443→  return derivedStatus;
444→}
