496→
497→  // If task-scoped, auto-update task status to in_progress
498→  if (input.taskId) {
499→    const taskRecord = new RecordId("task", input.taskId);
500→    const task = await input.surreal.select<TaskRow>(taskRecord);
501→    if (task && (task.status === "todo" || task.status === "ready")) {
502→      await input.surreal.update(taskRecord).merge({
503→        status: "in_progress",
504→        updated_at: now,
505→      });
506→    }
507→  }
508→
509→  return { session_id: toId(sessionRecord) };
510→}
