512→/** End an agent session with summary */
513→export async function endAgentSession(input: {
514→  surreal: Surreal;
515→  sessionId: string;
516→  summary: string;
517→  decisionsMade?: string[];
518→  questionsAsked?: string[];
519→  tasksProgressed?: Array<{ task_id: string; from_status: string; to_status: string }>;
520→  filesChanged?: Array<{ path: string; change_type: string }>;
521→  observationsLogged?: string[];
522→}): Promise<{ session_id: string; ended: boolean }> {
523→  const now = new Date();
524→  const sessionRecord = new RecordId("agent_session", input.sessionId);
525→
526→  await input.surreal.update(sessionRecord).merge({
527→    ended_at: now,
528→    summary: input.summary,
529→    ...(input.decisionsMade?.length
530→      ? { decisions_made: input.decisionsMade.map((id) => new RecordId("decision", id)) }
531→      : {}),
532→    ...(input.questionsAsked?.length
533→      ? { questions_asked: input.questionsAsked.map((id) => new RecordId("question", id)) }
534→      : {}),
535→    ...(input.tasksProgressed?.length
536→      ? {
537→          tasks_progressed: input.tasksProgressed.map((t) => ({
538→            task_id: new RecordId("task", t.task_id),
539→            from_status: t.from_status,
540→            to_status: t.to_status,
541→          })),
542→        }
543→      : {}),
544→    ...(input.filesChanged?.length ? { files_changed: input.filesChanged } : {}),
545→    ...(input.observationsLogged?.length
546→      ? { observations_logged: input.observationsLogged.map((id) => new RecordId("observation", id)) }
547→      : {}),
548→  });
549→
550→  // Create session -> entity edges
551→  if (input.decisionsMade?.length) {
552→    for (const decisionId of input.decisionsMade) {
553→      await input.surreal
554→        .relate(sessionRecord, new RecordId("produced", randomUUID()), new RecordId("decision", decisionId), {
555→          added_at: now,
556→        })
557→        .output("after");
558→    }
559→  }
560→
561→  if (input.questionsAsked?.length) {
562→    for (const questionId of input.questionsAsked) {
563→      await input.surreal
564→        .relate(sessionRecord, new RecordId("asked", randomUUID()), new RecordId("question", questionId), {
565→          added_at: now,
566→        })
567→        .output("after");
568→    }
569→  }
570→
571→  if (input.tasksProgressed?.length) {
572→    for (const t of input.tasksProgressed) {
573→      await input.surreal
574→        .relate(sessionRecord, new RecordId("progressed", randomUUID()), new RecordId("task", t.task_id), {
575→          from_status: t.from_status,
576→          to_status: t.to_status,
577→          added_at: now,
578→        })
579→        .output("after");
580→    }
581→  }
582→
583→  return { session_id: toId(sessionRecord), ended: true };
584→}
