355→  /** POST /api/mcp/:workspaceId/constraints/check — Check proposed action */
356→  async function handleCheckConstraints(workspaceId: string, request: Request): Promise<Response> {
357→    const auth = await requireAuth(request, workspaceId);
358→    if (auth instanceof Response) return auth;
359→
360→    const body = await parseJsonBody<{ proposed_action: string; project?: string }>(request);
361→    if (body instanceof Response) return body;
362→    if (!body.proposed_action) return jsonError("proposed_action is required", 400);
363→
364→    const queryEmbedding = await createEmbeddingVector(
365→      deps.embeddingModel,
366→      body.proposed_action,
367→      config.embeddingDimension,
368→    );
369→
370→    if (!queryEmbedding) {
371→      return jsonResponse({ hard_conflicts: [], soft_tensions: [], supporting: [], proceed: true }, 200);
372→    }
373→
374→    const projectRecord = body.project
375→      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.project })
376→      : undefined;
377→
378→    const candidates = await listDecisionConstraintCandidates({
379→      surreal,
380→      workspaceRecord: auth.workspaceRecord,
381→      queryEmbedding,
382→      ...(projectRecord ? { projectRecord } : {}),
383→      limit: 14,
384→    });
385→
386→    const actionTokens = normalizeTokens(body.proposed_action);
387→    const hardConflicts: Array<{ id: string; name: string; score: number; reason: string }> = [];
388→    const softTensions: Array<{ id: string; name: string; score: number; reason: string }> = [];
389→    const supporting: Array<{ id: string; name: string; score: number; reason: string }> = [];
390→
391→    for (const candidate of candidates) {
392→      const candidateTokens = normalizeTokens(candidate.name);
393→      const overlap = hasTokenOverlap(actionTokens, candidateTokens);
394→      const status = candidate.status?.toLowerCase();
395→
396→      if (candidate.kind === "decision" && overlap && (status === "contested" || status === "superseded")) {
397→        hardConflicts.push({
398→          id: `${candidate.kind}:${candidate.id}`,
399→          name: candidate.name,
400→          score: Number(candidate.score.toFixed(4)),
401→          reason: `Decision is marked ${status}.`,
402→        });
403→        continue;
404→      }
405→
406→      if (candidate.kind === "decision" && candidate.score >= 0.86 && overlap) {
407→        supporting.push({
408→          id: `${candidate.kind}:${candidate.id}`,
409→          name: candidate.name,
410→          score: Number(candidate.score.toFixed(4)),
411→          reason: "High-similarity decision aligns with proposed action.",
412→        });
413→        continue;
414→      }
415→
416→      if (candidate.score >= 0.72) {
417→        softTensions.push({
418→          id: `${candidate.kind}:${candidate.id}`,
419→          name: candidate.name,
420→          score: Number(candidate.score.toFixed(4)),
421→          reason: overlap
422→            ? "Related decision/question may require consistency checks."
423→            : "Semantically related context may be affected.",
424→        });
425→      }
426→    }
427→
428→    return jsonResponse({ hard_conflicts: hardConflicts, soft_tensions: softTensions, supporting, proceed: hardConflicts.length === 0 }, 200);
429→  }
