487→
488→    const body = await parseJsonBody<{
489→      text: string;
490→      context?: { project?: string; feature?: string; task?: string };
491→      options?: string[];
492→      blocking_task?: string;
493→    }>(request);
494→    if (body instanceof Response) return body;
495→    if (!body.text) return jsonError("text is required", 400);
496→
497→    const projectRecord = body.context?.project
498→      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.context.project })
499→      : undefined;
500→
501→    const featureRecord = body.context?.feature
502→      ? await resolveWorkspaceFeatureRecord({ surreal, workspaceRecord: auth.workspaceRecord, featureInput: body.context.feature })
503→      : undefined;
504→
505→    const questionRecord = await createQuestionRecord({
506→      surreal,
507→      text: body.text,
508→      status: "asked",
509→      now: new Date(),
510→      workspaceRecord: auth.workspaceRecord,
511→      ...(projectRecord ? { projectRecord } : {}),
512→      ...(featureRecord ? { featureRecord } : {}),
513→    });
514→
515→    // Set coding agent fields directly
516→    const now = new Date();
517→    await surreal.update(questionRecord).merge({
518→      asked_by: "code-agent",
519→      ...(body.options?.length ? { options: body.options } : {}),
520→      ...(body.blocking_task ? { blocking_task: new RecordId("task", body.blocking_task) } : {}),
