525→      const taskRecord = new RecordId("task", body.blocking_task);
526→      await surreal
527→        .relate(questionRecord, new RecordId("depends_on", crypto.randomUUID()), taskRecord, {
528→          type: "blocks",
529→          added_at: now,
530→        })
531→        .output("after");
532→    }
533→
534→    logInfo("mcp.question.created", "Question created via MCP", {
535→      workspaceId,
536→      questionId: questionRecord.id as string,
537→    });
538→
539→    return jsonResponse({
540→      question_id: `question:${questionRecord.id as string}`,
541→      status: "asked",
542→    }, 201);
