  1→import { randomUUID } from "node:crypto";
  2→import { RecordId, Surreal } from "surrealdb";
  3→import type { EntityCategory, ObservationSeverity, ObservationStatus, ObservationSummary, ObservationType } from "../../shared/contracts";
  4→
  5→type ObservationRecord = RecordId<"observation", string>;
  6→type ObserveTargetRecord = RecordId<"project" | "feature" | "task" | "decision" | "question", string>;
  7→
  8→const SEVERITY_PRIORITY: Record<ObservationSeverity, number> = {
  9→  conflict: 0,
 10→  warning: 1,
 11→  info: 2,
 12→};
 13→
 14→export async function createObservation(input: {
 15→  surreal: Surreal;
 16→  workspaceRecord: RecordId<"workspace", string>;
 17→  text: string;
 18→  severity: ObservationSeverity;
 19→  category?: EntityCategory;
 20→  observationType?: ObservationType;
 21→  sourceAgent: string;
 22→  now: Date;
 23→  sourceMessageRecord?: RecordId<"message", string>;
 24→  sourceSessionRecord?: RecordId<"agent_session", string>;
 25→  relatedRecord?: ObserveTargetRecord;
 26→  embedding?: number[];
 27→}): Promise<ObservationRecord> {
 28→  const observationRecord = new RecordId("observation", randomUUID());
 29→
 30→  await input.surreal.create(observationRecord).content({
 31→    text: input.text,
 32→    severity: input.severity,
 33→    status: "open",
 34→    ...(input.category ? { category: input.category } : {}),
 35→    ...(input.observationType ? { observation_type: input.observationType } : {}),
 36→    source_agent: input.sourceAgent,
 37→    workspace: input.workspaceRecord,
 38→    ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
 39→    ...(input.sourceSessionRecord ? { source_session: input.sourceSessionRecord } : {}),
 40→    ...(input.embedding ? { embedding: input.embedding } : {}),
 41→    created_at: input.now,
 42→    updated_at: input.now,
 43→  });
 44→
 45→  if (input.relatedRecord) {
 46→    await input.surreal
 47→      .relate(observationRecord, new RecordId("observes", randomUUID()), input.relatedRecord, {
 48→        added_at: input.now,
 49→      })
 50→      .output("after");
 51→  }
 52→
 53→  return observationRecord;
 54→}
 55→
 56→export async function acknowledgeObservation(input: {
 57→  surreal: Surreal;
 58→  workspaceRecord: RecordId<"workspace", string>;
 59→  observationRecord: ObservationRecord;
 60→  now: Date;
 61→}): Promise<void> {
 62→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.observationRecord);
 63→  if (!row) {
 64→    throw new Error(`observation not found: ${input.observationRecord.id as string}`);
 65→  }
 66→
 67→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
 68→    throw new Error("observation is outside the current workspace scope");
 69→  }
 70→
 71→  await input.surreal.update(input.observationRecord).merge({
 72→    status: "acknowledged" satisfies ObservationStatus,
 73→    updated_at: input.now,
 74→  });
 75→}
 76→
 77→export async function resolveObservation(input: {
 78→  surreal: Surreal;
 79→  workspaceRecord: RecordId<"workspace", string>;
 80→  observationRecord: ObservationRecord;
 81→  now: Date;
 82→  resolvedByRecord?: RecordId<"person", string>;
 83→}): Promise<void> {
 84→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.observationRecord);
 85→  if (!row) {
 86→    throw new Error(`observation not found: ${input.observationRecord.id as string}`);
 87→  }
 88→
 89→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
 90→    throw new Error("observation is outside the current workspace scope");
 91→  }
 92→
 93→  await input.surreal.update(input.observationRecord).merge({
 94→    status: "resolved" satisfies ObservationStatus,
 95→    resolved_at: input.now,
 96→    ...(input.resolvedByRecord ? { resolved_by: input.resolvedByRecord } : {}),
 97→    updated_at: input.now,
 98→  });
 99→}
