119→/** Get task dependency tree (recursive) */
120→export async function getTaskDependencyTree(input: {
121→  surreal: Surreal;
122→  taskRecord: RecordId<"task", string>;
123→}): Promise<{
124→  task: { id: string; title: string; status: string };
125→  dependencies: Array<{ id: string; title: string; status: string; resolved: boolean }>;
126→  dependents: Array<{ id: string; title: string; status: string }>;
127→  subtasks: Array<{ id: string; title: string; status: string }>;
128→}> {
129→  const task = await input.surreal.select<TaskRow>(input.taskRecord);
130→  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
131→
132→  const query = `
133→    -- Tasks this task depends on
134→    SELECT id, title, status
135→    FROM task
136→    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
137→
138→    -- Tasks that depend on this task
139→    SELECT id, title, status
140→    FROM task
141→    WHERE id IN (SELECT VALUE \`in\` FROM depends_on WHERE out = $task);
142→
143→    -- Subtasks
144→    SELECT id, title, status
145→    FROM task
146→    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
147→    ORDER BY created_at ASC;
148→  `;
149→
150→  const results = await input.surreal
151→    .query<[DependencyRow[], DependencyRow[], SubtaskRow[]]>(query, { task: input.taskRecord })
152→    .collect<[DependencyRow[], DependencyRow[], SubtaskRow[]]>();
153→
154→  const [deps, dependents, subtasks] = results;
155→
156→  return {
157→    task: { id: toId(task.id), title: task.title, status: task.status },
158→    dependencies: deps.map((d) => ({
159→      id: toId(d.id),
160→      title: d.title,
161→      status: d.status,
162→      resolved: d.status === "done" || d.status === "completed",
163→    })),
164→    dependents: dependents.map((d) => ({ id: toId(d.id), title: d.title, status: d.status })),
165→    subtasks: subtasks.map((s) => ({ id: toId(s.id), title: s.title, status: s.status })),
166→  };
167→}
