283→/** Create a subtask with semantic dedup */
284→export async function createSubtask(input: {
285→  surreal: Surreal;
286→  parentTaskRecord: RecordId<"task", string>;
287→  title: string;
288→  workspaceRecord: RecordId<"workspace", string>;
289→  category?: string;
290→  rationale?: string;
291→}): Promise<{ task_id: string; parent_task_id: string; already_existed: boolean }> {
292→  // Check for existing similar subtasks (semantic dedup by title)
293→  const normalizedTitle = input.title.toLowerCase().trim();
294→
295→  const [existingRows] = await input.surreal
296→    .query<[SubtaskRow[]]>(
297→      `SELECT id, title, status
298→       FROM task
299→       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent)
300→       ORDER BY created_at ASC;`,
301→      { parent: input.parentTaskRecord },
302→    )
303→    .collect<[SubtaskRow[]]>();
304→
305→  // Simple dedup: check if any existing subtask title is very similar
306→  for (const existing of existingRows) {
307→    const existingNormalized = existing.title.toLowerCase().trim();
308→    if (existingNormalized === normalizedTitle || levenshteinSimilarity(existingNormalized, normalizedTitle) > 0.85) {
309→      return {
310→        task_id: toId(existing.id),
311→        parent_task_id: toId(input.parentTaskRecord),
312→        already_existed: true,
313→      };
314→    }
315→  }
316→
317→  // Get parent task's category if not specified
318→  const parentTask = await input.surreal.select<TaskRow>(input.parentTaskRecord);
319→  if (!parentTask) throw new Error(`parent task not found: ${input.parentTaskRecord.id}`);
320→
321→  const now = new Date();
322→  const taskRecord = new RecordId("task", randomUUID());
323→
324→  await input.surreal.create(taskRecord).content({
325→    title: input.title,
326→    status: "todo",
327→    created_at: now,
328→    updated_at: now,
329→    workspace: input.workspaceRecord,
330→    ...(input.category ? { category: input.category } : parentTask.category ? { category: parentTask.category } : {}),
331→    ...(input.rationale ? { description: input.rationale } : {}),
332→  });
333→
334→  // Create subtask_of edge
335→  await input.surreal
336→    .relate(taskRecord, new RecordId("subtask_of", randomUUID()), input.parentTaskRecord, {
337→      added_at: now,
338→    })
339→    .output("after");
340→
341→  // Copy belongs_to edges from parent (inherit project/feature)
342→  const [parentBelongsTo] = await input.surreal
343→    .query<[Array<{ out: RecordId }>]>(
344→      "SELECT out FROM belongs_to WHERE `in` = $parent;",
345→      { parent: input.parentTaskRecord },
346→    )
347→    .collect<[Array<{ out: RecordId }>]>();
348→
349→  for (const edge of parentBelongsTo) {
350→    await input.surreal
351→      .relate(taskRecord, new RecordId("belongs_to", randomUUID()), edge.out, {
352→        added_at: now,
353→      })
354→      .output("after");
355→  }
356→
357→  return {
358→    task_id: toId(taskRecord),
359→    parent_task_id: toId(input.parentTaskRecord),
360→    already_existed: false,
361→  };
362→}
