 89→/** Build a broad project context packet (all decisions, tasks, questions for a project) */
 90→export async function buildProjectContext(input: {
 91→  surreal: Surreal;
 92→  workspaceRecord: RecordId<"workspace", string>;
 93→  workspaceName: string;
 94→  projectRecord: RecordId<"project", string>;
 95→  taskId?: string;
 96→  since?: string;
 97→}): Promise<ContextPacket> {
 98→  const { surreal, workspaceRecord, workspaceName, projectRecord, taskId } = input;
 99→
100→  // Load project details
101→  const project = await surreal.select<ProjectRow>(projectRecord);
102→  if (!project) {
103→    throw new Error(`project not found: ${projectRecord.id}`);
104→  }
105→
106→  // Load project-scoped entities in parallel
107→  const projectEntitiesQuery = `
108→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
109→
110→    SELECT id, summary, status, rationale, decided_at, category, priority
111→    FROM decision
112→    WHERE workspace = $workspace AND id IN $project_entity_ids
113→    ORDER BY created_at DESC LIMIT 50;
114→
115→    SELECT id, title, status, priority, category, description
116→    FROM task
117→    WHERE workspace = $workspace AND id IN $project_entity_ids
118→    ORDER BY created_at DESC LIMIT 50;
119→
120→    SELECT id, text, status, context, priority
121→    FROM question
122→    WHERE workspace = $workspace AND id IN $project_entity_ids
123→    ORDER BY created_at DESC LIMIT 30;
124→
125→    SELECT id, text, severity, status, category, observation_type
126→    FROM observation
127→    WHERE workspace = $workspace AND status IN ["open", "acknowledged"]
128→    ORDER BY created_at DESC LIMIT 20;
129→  `;
130→
131→  const results = await surreal
132→    .query<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>(projectEntitiesQuery, {
133→      project: projectRecord,
134→      workspace: workspaceRecord,
135→    })
136→    .collect<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>();
137→
138→  const [, decisionRows, taskRows, questionRows, observationRows] = results;
139→
140→  // Categorize decisions by status
141→  const confirmed: DecisionContext[] = [];
142→  const provisional: DecisionContext[] = [];
143→  const contested: DecisionContext[] = [];
144→
145→  for (const d of decisionRows) {
146→    const ctx: DecisionContext = {
147→      id: toId(d.id),
148→      summary: d.summary,
149→      status: d.status,
150→      ...(d.rationale ? { rationale: d.rationale } : {}),
151→      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
152→      ...(d.category ? { category: d.category } : {}),
153→      ...(d.priority ? { priority: d.priority } : {}),
154→    };
155→
156→    if (d.status === "contested") {
157→      contested.push(ctx);
158→    } else if (d.status === "provisional" || d.status === "inferred") {
159→      provisional.push(ctx);
160→    } else if (d.status === "confirmed") {
161→      confirmed.push(ctx);
162→    }
163→  }
164→
165→  // Map tasks
166→  const activeTasks: TaskContext[] = taskRows
167→    .filter((t) => t.status !== "done" && t.status !== "completed")
168→    .map((t) => ({
169→      id: toId(t.id),
170→      title: t.title,
171→      status: t.status,
172→      ...(t.priority ? { priority: t.priority } : {}),
173→      ...(t.category ? { category: t.category } : {}),
174→    }));
175→
176→  // Map questions
177→  const openQuestions: QuestionContext[] = questionRows
178→    .filter((q) => q.status !== "answered" && q.status !== "resolved")
179→    .map((q) => ({
180→      id: toId(q.id),
181→      text: q.text,
182→      status: q.status,
183→      ...(q.context ? { context: q.context } : {}),
184→      ...(q.priority ? { priority: q.priority } : {}),
185→    }));
186→
187→  // Map observations
188→  const observations: ObservationContext[] = observationRows.map((o) => ({
189→    id: toId(o.id),
190→    text: o.text,
191→    severity: o.severity,
192→    status: o.status,
193→    ...(o.category ? { category: o.category } : {}),
194→    ...(o.observation_type ? { observation_type: o.observation_type } : {}),
195→  }));
196→
197→  // Build recent changes if `since` provided
198→  const recentChanges: RecentChangeContext[] = input.since
199→    ? await loadRecentChanges(surreal, workspaceRecord, projectRecord, input.since)
200→    : [];
201→
202→  // Build task scope if taskId provided
203→  let taskScope: TaskScopeContext | undefined;
204→  if (taskId) {
205→    taskScope = await buildTaskScope(surreal, workspaceRecord, projectRecord, taskId);
206→  }
207→
208→  return {
209→    workspace: { id: workspaceRecord.id as string, name: workspaceName },
210→    project: {
211→      id: projectRecord.id as string,
212→      name: project.name,
213→      status: project.status,
214→      ...(project.description ? { description: project.description } : {}),
215→    },
216→    ...(taskScope ? { task_scope: taskScope } : {}),
217→    decisions: { confirmed, provisional, contested },
218→    active_tasks: activeTasks,
219→    open_questions: openQuestions,
220→    recent_changes: recentChanges,
221→    observations,
222→  };
223→}
