329→/** Load entities changed since a timestamp for the recent_changes field */
330→async function loadRecentChanges(
331→  surreal: Surreal,
332→  workspaceRecord: RecordId<"workspace", string>,
333→  projectRecord: RecordId<"project", string>,
334→  since: string,
335→): Promise<RecentChangeContext[]> {
336→  const sinceDate = new Date(since);
337→
338→  const query = `
339→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
340→
341→    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
342→    FROM decision
343→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
344→    ORDER BY updated_at DESC LIMIT 20;
345→
346→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
347→    FROM task
348→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
349→    ORDER BY updated_at DESC LIMIT 20;
350→
351→    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
352→    FROM question
353→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
354→    ORDER BY updated_at DESC LIMIT 20;
355→
356→    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions]);
357→  `;
358→
359→  const results = await surreal
360→    .query<[null, null, null, null, RecentChangeRow[]]>(query, {
361→      project: projectRecord,
362→      workspace: workspaceRecord,
363→      since: sinceDate,
364→    })
365→    .collect<[null, null, null, null, RecentChangeRow[]]>();
366→
367→  const rows = results[4] ?? [];
368→
369→  return rows.map((r) => ({
370→    entity_type: r.entity_type,
371→    entity_name: r.entity_name,
372→    change_type: r.change_type,
373→    changed_at: toIso(r.changed_at),
374→  }));
375→}
376→
377→type RecentChangeRow = {
378→  entity_type: string;
379→  entity_name: string;
380→  change_type: string;
381→  changed_at: Date | string;
382→};
