 80→// ---------------------------------------------------------------------------
 81→// Route handlers
 82→// ---------------------------------------------------------------------------
 83→
 84→export function createMcpRouteHandlers(deps: ServerDependencies) {
 85→  const { surreal, config, extractionModel } = deps;
 86→
 87→  // ---- Auth helper: returns McpAuthResult or error Response ----
 88→  async function requireAuth(request: Request, workspaceId: string): Promise<McpAuthResult | Response> {
 89→    return authenticateMcpRequest(request, workspaceId, surreal);
 90→  }
 91→
 92→  // ---- Workspace helper (no auth - for legacy/unauthenticated routes) ----
 93→  async function resolveWorkspaceById(workspaceId: string): Promise<{ workspaceRecord: RecordId<"workspace", string>; workspace: WorkspaceRow } | Response> {
 94→    const workspaceRecord = new RecordId("workspace", workspaceId);
 95→    const workspace = await surreal.select<WorkspaceRow>(workspaceRecord);
 96→    if (!workspace) return jsonError("workspace not found", 404);
 97→    return { workspaceRecord, workspace };
 98→  }
 99→
100→  // =========================================================================
101→  // Setup
102→  // =========================================================================
103→
104→  /** POST /api/mcp/:workspaceId/auth/init — Generate API key */
105→  async function handleAuthInit(workspaceId: string): Promise<Response> {
106→    const result = await resolveWorkspaceById(workspaceId);
107→    if (result instanceof Response) return result;
108→
109→    const apiKey = generateApiKey();
110→    const hash = await hashApiKey(apiKey);
111→
112→    await surreal.update(result.workspaceRecord).merge({ api_key_hash: hash, updated_at: new Date() });
113→
114→    logInfo("mcp.auth.init", "API key generated for workspace", { workspaceId });
115→
116→    return jsonResponse({ api_key: apiKey, workspace: { id: workspaceId, name: result.workspace.name } }, 200);
117→  }
118→
119→  /** GET /api/mcp/:workspaceId/projects — List workspace projects */
120→  async function handleListProjects(workspaceId: string): Promise<Response> {
121→    const result = await resolveWorkspaceById(workspaceId);
122→    if (result instanceof Response) return result;
123→
124→    const [projectRows] = await surreal
125→      .query<[ProjectRow[]]>(
126→        "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
127→        { workspace: result.workspaceRecord },
128→      )
129→      .collect<[ProjectRow[]]>();
130→
131→    return jsonResponse({
132→      workspace: { id: workspaceId, name: result.workspace.name },
133→      projects: projectRows.map((p) => ({ id: p.id.id as string, name: p.name })),
134→    }, 200);
135→  }
136→
137→  // =========================================================================
138→  // Tier 1 — Read
139→  // =========================================================================
140→
141→  /** POST /api/mcp/:workspaceId/context — Get project context (broad or task-scoped) */
142→  async function handleGetContext(workspaceId: string, request: Request): Promise<Response> {
143→    const auth = await requireAuth(request, workspaceId);
144→    if (auth instanceof Response) return auth;
145→
146→    const body = await parseJsonBody<{ project_id: string; task_id?: string; since?: string }>(request);
147→    if (body instanceof Response) return body;
148→    if (!body.project_id) return jsonError("project_id is required", 400);
149→
150→    const projectRecord = new RecordId("project", body.project_id);
151→    const project = await surreal.select<ProjectRow>(projectRecord);
152→    if (!project) return jsonError("project not found", 404);
153→
154→    try {
155→      const contextPacket = await buildProjectContext({
156→        surreal,
157→        workspaceRecord: auth.workspaceRecord,
158→        workspaceName: auth.workspaceName,
159→        projectRecord,
160→        taskId: body.task_id,
161→        since: body.since,
162→      });
163→
164→      logInfo("mcp.context.built", "MCP context packet assembled", {
165→        workspaceId,
166→        projectId: body.project_id,
167→        taskId: body.task_id,
168→        decisionsCount:
169→          contextPacket.decisions.confirmed.length +
170→          contextPacket.decisions.provisional.length +
171→          contextPacket.decisions.contested.length,
172→        tasksCount: contextPacket.active_tasks.length,
173→      });
174→
175→      return jsonResponse(contextPacket, 200);
176→    } catch (error) {
177→      logError("mcp.context.failed", "Failed to build MCP context", error);
178→      return jsonError("failed to build context", 500);
179→    }
180→  }
