533→
534→    logInfo("mcp.question.created", "Question created via MCP", {
535→      workspaceId,
536→      questionId: questionRecord.id as string,
537→    });
538→
539→    return jsonResponse({
540→      question_id: `question:${questionRecord.id as string}`,
541→      status: "asked",
542→    }, 201);
