import { RecordId, type Surreal } from "surrealdb";
import type {
  ContextPacket,
  DecisionContext,
  TaskContext,
  QuestionContext,
  ObservationContext,
  TaskScopeContext,
  RecentChangeContext,
} from "./types";

type ProjectRow = {
  id: RecordId<"project", string>;
  name: string;
  status: string;
  description?: string;
};

type DecisionRow = {
  id: RecordId<"decision", string>;
  summary: string;
  status: string;
  rationale?: string;
  decided_at?: Date | string;
  category?: string;
  priority?: string;
};

type TaskRow = {
  id: RecordId<"task", string>;
  title: string;
  status: string;
  priority?: string;
