           AND id != $task
         ORDER BY created_at ASC LIMIT 20;`,
        { feature: featureRows[0].id, task: taskRecord },
      )
      .collect<[TaskRow[]]>();

    siblingTasks = siblingRows.map((t) => ({
      id: toId(t.id),
      title: t.title,
      status: t.status,
    }));
  }

  return {
    task: {
      id: toId(task.id),
      title: task.title,
      ...(task.description ? { description: task.description } : {}),
      status: task.status,
      ...(task.category ? { category: task.category } : {}),
    },
    subtasks: subtaskRows.map((s) => ({
      id: toId(s.id),
      title: s.title,
      status: s.status,
    })),
    parent_feature: parentFeature,
    sibling_tasks: siblingTasks,
    dependencies: dependencyRows.map((d) => ({
      id: toId(d.id),
      title: d.title,
      status: d.status,
    })),
    related_sessions: sessionRows.map((s) => ({
      id: toId(s.id),
      agent: s.agent,
      ended_at: toIso(s.ended_at),
      summary: s.summary ?? "",
    })),
  };
}

